class MainActivity : AppCompatActivity() {

    private lateinit var webView: WebView
    private val TAG = "WebViewWrapper"
    private val CAMERA_PERMISSION_REQUEST_CODE = 101
    private val NOTIFICATION_CHANNEL_ID = "webview_notifications"
    private val NOTIFICATION_CHANNEL_NAME = "Web App Notifications"

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main) // Assuming you have an activity_main.xml with a WebView

        webView = findViewById(R.id.webView)
        setupWebView()
        createNotificationChannel()

        // Handle back button presses within the WebView history
        onBackPressedDispatcher.addCallback(this, object : OnBackPressedCallback(true) {
            override fun handleOnBackPressed() {
                if (webView.canGoBack()) {
                    webView.goBack()
                } else {
                    finish()
                }
            }
        })

        // Load your web app URL
        // For demonstration, you might load a local HTML file or a remote URL.
        // If loading a local file, ensure it's in src/main/assets/
        // webView.loadUrl("file:///android_asset/mywebapp.html")
        webView.loadUrl("https://www.google.com/") // Replace with your actual web app URL
    }

    @SuppressLint("SetJavaScriptEnabled")
    private fun setupWebView() {
        // Enable JavaScript
        webView.settings.javaScriptEnabled = true

        // Add the JavaScript interface
        // The second argument "AndroidBridge" is the name the JavaScript code will use to access native methods.
        webView.addJavascriptInterface(AndroidBridge(this), "AndroidBridge")

        // Set a WebViewClient to handle page navigation within the WebView
        webView.webViewClient = object : WebViewClient() {
            override fun onPageStarted(view: WebView?, url: String?, favicon: Bitmap?) {
                super.onPageStarted(view, url, favicon)
                Log.d(TAG, "Page started loading: $url")
            }

            override fun onPageFinished(view: WebView?, url: String?) {
                super.onPageFinished(view, url)
                Log.d(TAG, "Page finished loading: $url")
            }

            override fun onReceivedError(
                view: WebView?,
                errorCode: Int,
                description: String?,
                failingUrl: String?
            ) {
                super.onReceivedError(view, errorCode, description, failingUrl)
                Log.e(TAG, "WebView Error: $errorCode - $description on $failingUrl")
                Toast.makeText(
                    this@MainActivity,
                    "Error loading page: $description",
                    Toast.LENGTH_LONG
                ).show()
            }
        }

        // Set a WebChromeClient to handle JavaScript dialogs (alert, confirm, prompt)
        // and progress changes, also crucial for console.log output.
        webView.webChromeClient = object : WebChromeClient() {
            override fun onProgressChanged(view: WebView?, newProgress: Int) {
                super.onProgressChanged(view, newProgress)
                Log.d(TAG, "Loading progress: $newProgress%")
            }

            override fun onConsoleMessage(consoleMessage: android.webkit.ConsoleMessage?): Boolean {
                consoleMessage?.apply {
                    Log.d(
                        TAG, "JS Console: ${message()} -- From line ${lineNumber()} of ${sourceId()}"
                    )
                }
                return true
            }

            // You can override onJsAlert, onJsConfirm, onJsPrompt here to customize dialogs
        }

        // Other useful settings
        webView.settings.domStorageEnabled = true // Enable DOM storage (localStorage, sessionStorage)
        webView.settings.databaseEnabled = true // Enable database storage (deprecated)
        webView.settings.allowFileAccess = true // Allow access to file URLs
        webView.settings.allowContentAccess = true // Allow access to content URLs
