        // webView.settings.mixedContentMode = WebSettings.MIXED_CONTENT_ALWAYS_ALLOW // For HTTPS pages loading HTTP resources
    }

    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val name = NOTIFICATION_CHANNEL_NAME
            val descriptionText = "Notifications from the web application"
            val importance = NotificationManager.IMPORTANCE_DEFAULT
            val channel = NotificationChannel(NOTIFICATION_CHANNEL_ID, name, importance).apply {
                description = descriptionText
            }
            val notificationManager: NotificationManager =
                getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
            notificationManager.createNotificationChannel(channel)
        }
    }

    override fun onRequestPermissionsResult(
        requestCode: Int,
        permissions: Array<out String>,
        grantResults: IntArray
    ) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults)
        when (requestCode) {
            CAMERA_PERMISSION_REQUEST_CODE -> {
                if ((grantResults.isNotEmpty() && grantResults[0] == PackageManager.PERMISSION_GRANTED)) {
                    Toast.makeText(this, "Camera permission granted!", Toast.LENGTH_SHORT).show()
                    // If you need to immediately open camera after permission, do it here
                } else {
                    Toast.makeText(this, "Camera permission denied!", Toast.LENGTH_SHORT).show()
                }
                return
            }
            // Handle other permission requests if any
        }
    }

    inner class AndroidBridge(private val context: Context) {

        private val sharedPreferences =
            context.getSharedPreferences("WebViewLocalStorage", Context.MODE_PRIVATE)

        @JavascriptInterface
        fun showToast(message: String) {
            Toast.makeText(context, message, Toast.LENGTH_SHORT).show()
            Log.d(TAG, "JS called showToast: $message")
        }

        @JavascriptInterface
        fun requestCameraAccess(callbackId: String) {
            Log.d(TAG, "JS requested camera access (callbackId: $callbackId)")
            if (ContextCompat.checkSelfPermission(
                    context,
                    Manifest.permission.CAMERA
                ) != PackageManager.PERMISSION_GRANTED
            ) {
                // Request the permission
                ActivityCompat.requestPermissions(
                    this@MainActivity,
                    arrayOf(Manifest.permission.CAMERA),
                    CAMERA_PERMISSION_REQUEST_CODE
                )
                // Note: The actual result is handled in onRequestPermissionsResult
                // You might want to queue the callbackId and respond there.
                // For simplicity here, we assume permission will be granted or denied later.
            } else {
                Toast.makeText(context, "Camera access already granted.", Toast.LENGTH_SHORT)
                    .show()
                // If permission is already granted, immediately respond to JS
                // Example: Call a JavaScript function back with the status
                // webView.post { webView.evaluateJavascript("window.onCameraPermissionResult('$callbackId', true)", null) }
            }
        }

        @JavascriptInterface
        fun saveLocalStorage(key: String, value: String) {
            Log.d(TAG, "JS requested to save data: $key = $value")
            sharedPreferences.edit().putString(key, value).apply()
            Toast.makeText(context, "Saved: $key=$value", Toast.LENGTH_SHORT).show()
        }

        @JavascriptInterface
        fun getLocalStorage(key: String, callbackId: String) {
            val value = sharedPreferences.getString(key, null)
            Log.d(TAG, "JS requested to get data for key: $key -> Value: $value (callbackId: $callbackId)")
            // Call JavaScript function back with the retrieved value
            webView.post {
                webView.evaluateJavascript(
                    "window.onDataRetrievedCallback('$callbackId', '${value ?: "null"}')",
                    null
                )
            }
        }

        @JavascriptInterface
        fun showPushNotification(title: String, message: String) {
            Log.d(TAG, "JS requested push notification: Title: $title, Message: $message")

            val notificationId = System.currentTimeMillis().toInt() // Unique ID for each notification

            val builder = NotificationCompat.Builder(context, NOTIFICATION_CHANNEL_ID)
                .setSmallIcon(R.drawable.ic_notification) // Ensure you have an ic_notification drawable
                .setContentTitle(title)
                .setContentText(message)
                .setPriority(NotificationCompat.PRIORITY_DEFAULT)
                .setAutoCancel(true) // Automatically dismiss the notification when the user taps it

            val notificationManager =
                context.getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
            notificationManager.notify(notificationId, builder.build())

            Toast.makeText(context, "Notification shown: $title", Toast.LENGTH_SHORT).show()
        }
    }
}

